 /// SimplifyIVUsers helper for eliminating useless
 /// comparisons against an induction variable.
+static bool containsPoisonousUDiv(const SCEV *S) {
+  // Look for SCEVUDivExpr with a constant zero RHS.
+  if (const auto *UD = dyn_cast<SCEVUDivExpr>(S)) {
+    if (const auto *C = dyn_cast<SCEVConstant>(UD->getRHS()))
+      if (C->getAPInt().isZero())
+        return true;
+    // Also recurse into operands to catch nested cases.
+    if (containsPoisonousUDiv(UD->getLHS()) || containsPoisonousUDiv(UD->getRHS()))
+      return true;
+  }
+  // Recurse through generic n-ary expressions.
+  if (const auto *NAE = dyn_cast<SCEVNAryExpr>(S)) {
+    for (const SCEV *Op : NAE->operands())
+      if (containsPoisonousUDiv(Op))
+        return true;
+  }
+  // AddRec: recurse into start/step.
+  if (const auto *AR = dyn_cast<SCEVAddRecExpr>(S)) {
+    if (containsPoisonousUDiv(AR->getStart()) || containsPoisonousUDiv(AR->getStepRecurrence(*AR->getSE())))
+      return true;
+  }
+  return false;
+}
